create or replace function public.audit_claim_payment_insert()returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.audit_logs(organization_id,user_id,actor_user_id,actor_role,action,entity_type,entity_id,amount_after,remarks,source,new_values)select new.organization_id,new.created_by,new.created_by,public.current_user_role(),'claims.payment_'||case when v.payment_status='paid' then 'full' else 'partial' end,'claim',i.claim_id,new.payment_amount,new.remarks,'web',jsonb_build_object('voucherId',new.voucher_id,'paymentId',new.id,'reference',new.payment_reference)from public.claim_payment_voucher_items i join public.claim_payment_vouchers v on v.id=i.voucher_id where i.voucher_id=new.voucher_id group by i.claim_id,v.payment_status;return new;end $$;
create trigger audit_claim_payment after insert on public.claim_payments for each row execute function public.audit_claim_payment_insert();
create or replace function public.audit_sap_item_insert()returns trigger language plpgsql security definer set search_path=public as $$ declare b public.claim_sap_export_batches%rowtype;begin select * into b from public.claim_sap_export_batches where id=new.sap_batch_id;if not exists(select 1 from public.audit_logs where entity_type='claim' and entity_id=new.claim_id and new_values->>'batchId'=b.id::text)then insert into public.audit_logs(organization_id,user_id,actor_user_id,actor_role,action,entity_type,entity_id,amount_after,remarks,source,new_values)values(b.organization_id,b.exported_by,b.exported_by,public.current_user_role(),'claims.sap_'||b.export_type||'_generated','claim',new.claim_id,new.amount,b.remarks,'web',jsonb_build_object('batchId',b.id,'batchNumber',b.sap_batch_number));end if;return new;end $$;
create trigger audit_sap_item after insert on public.claim_sap_export_items for each row execute function public.audit_sap_item_insert();
create or replace function public.audit_advance_insert()returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.audit_logs(organization_id,user_id,actor_user_id,actor_role,action,entity_type,entity_id,amount_after,remarks,new_values)values(new.organization_id,new.created_by,new.created_by,public.current_user_role(),'employee.advance_added','employee_advance',new.id,new.amount,new.remarks,jsonb_build_object('employeeId',new.employee_id,'type',new.advance_type));return new;end $$;
create trigger audit_employee_advance after insert on public.employee_advances for each row execute function public.audit_advance_insert();
create or replace function public.audit_signature_change()returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.audit_logs(organization_id,user_id,actor_user_id,actor_role,action,entity_type,entity_id,new_values)values(new.organization_id,coalesce(new.uploaded_by,auth.uid()),coalesce(new.uploaded_by,auth.uid()),public.current_user_role(),case when new.is_active then 'signature.activated' else 'signature.deactivated' end,'user_signature',new.id,jsonb_build_object('userId',new.user_id,'path',new.signature_path));return new;end $$;
create trigger audit_user_signature after insert or update of is_active on public.user_signatures for each row execute function public.audit_signature_change();
